//! GoodOS 内核二进制 crate —— 架构入口、内嵌用户程序、模块组装。

#![no_std]
#![no_main]
#![allow(dead_code)]
#![allow(warnings)]

use core::arch::global_asm;
use task;

#[cfg(target_arch = "riscv64")]
global_asm!(
    r#"
    .section .text.entry
    .globl _start
_start:
    bnez a0, _secondary_hart_park
    .option push
    .option norelax
    la   gp, __global_pointer$
    .option pop
    lla  sp, boot_stack_top
    mv   a0, a1
    call rust_main

_secondary_hart_park:
    wfi
    j _secondary_hart_park

    .section .boot_stack, "aw", @nobits
    .align 12
boot_stack:
    .space 262144
boot_stack_top:
"#
);

#[cfg(target_arch = "loongarch64")]
global_asm!(
    r#"
    .section .text.entry
    .globl _start
_start:
    la.local $sp, boot_stack_top
    or       $r4, $r5, $r0
    bl       rust_main
1:
    idle     0
    b        1b

    .section .bss.boot_stack
    .align 12
boot_stack:
    .space 262144
boot_stack_top:
"#
);

