/// 进入调度器循环，永不返回。
pub fn run() -> ! {
    loop {
        match task::fetch_next_task() {
            Some(tcb) => {
                task::run_task(&tcb);
            }
            None => {
                core::hint::spin_loop();
            }
        }
    }
}

