pub use platform::{PAGE_SIZE, PAGE_BITS};

/// Number of PTE slots per page-table page (512 for Sv39 / LA64).
pub const PTE_COUNT: usize = 512;

/// Architecture page-table flags.
#[cfg(target_arch = "riscv64")]
pub mod pte_flags {
    pub const V: usize = 1 << 0;
    pub const R: usize = 1 << 1;
    pub const W: usize = 1 << 2;
    pub const X: usize = 1 << 3;
    pub const U: usize = 1 << 4;
    pub const G: usize = 1 << 5;
    pub const A: usize = 1 << 6;
    pub const D: usize = 1 << 7;
    /// Software-defined Copy-on-Write flag (bit 8, reserved for S-mode).
    pub const COW: usize = 1 << 8;

    pub const USER_R:   usize = V | R | U | A | D;
    pub const USER_RW:  usize = V | R | W | U | A | D;
    pub const USER_RX:  usize = V | R | X | U | A | D;
    pub const USER_RWX: usize = V | R | W | X | U | A | D;
    pub const KERNEL_RX: usize = V | R | X | A | D;
    pub const KERNEL_RW:  usize = V | R | W | A | D;
    pub const KERNEL_RWX: usize = V | R | W | X | A | D;
}

#[cfg(target_arch = "loongarch64")]
pub mod pte_flags {
    pub const V: usize = 1 << 0;
    pub const D: usize = 1 << 1;
    pub const U: usize = 3 << 2;
    pub const G: usize = 1 << 6;
    pub const P: usize = 1 << 7;
    pub const W: usize = 1 << 8;
    pub const COW: usize = 1 << 9;
    pub const NR: usize = 1 << 61;
    pub const NX: usize = 1 << 62;

    pub const R: usize = 0;
    pub const X: usize = 0;
    pub const A: usize = 0;
    const MAT_CC: usize = 0 << 4;

    pub const USER_R: usize = P | V | D | U | MAT_CC | NX;
    pub const USER_RW: usize = P | V | D | U | MAT_CC | W | NX;
    pub const USER_RX: usize = P | V | D | U | MAT_CC;
    pub const USER_RWX: usize = P | V | D | U | MAT_CC | W;
    pub const KERNEL_RX: usize = P | V | D | G | MAT_CC;
    pub const KERNEL_RW: usize = P | V | D | G | W | MAT_CC | NX;
    pub const KERNEL_RWX: usize = P | V | D | G | W | MAT_CC;
}

// ── Helpers ────────────────────────────────────────────────────────────────

/// Round down to `align` (must be power of two).
pub fn align_down(value: usize, align: usize) -> usize {
    value & !(align - 1)
}

/// Round up to `align` (must be power of two).
pub fn align_up(value: usize, align: usize) -> usize {
    (value + align - 1) & !(align - 1)
}

#[cfg(target_arch = "loongarch64")]
const LA64_DMW_BASE: usize = 0x9000_0000_0000_0000;

/// 物理地址 → 内核可解引用的虚拟地址。
///
/// RISC-V：恒等映射，直接返回 pa。
/// LoongArch：通过 DMW 窗口转换（pa | 0x9000_0000_0000_0000），
/// 内核在用户 PGDL 下仍可通过高地址访问物理内存，无需在每个进程中
/// 复制低地址恒等映射。
#[inline(always)]
pub fn phys_to_virt(pa: usize) -> usize {
    #[cfg(target_arch = "loongarch64")]
    {
        LA64_DMW_BASE | pa
    }
    #[cfg(not(target_arch = "loongarch64"))]
    {
        pa
    }
}

/// 虚拟地址 → 物理地址（逆向转换）。
#[inline(always)]
pub fn virt_to_phys(va: usize) -> usize {
    #[cfg(target_arch = "loongarch64")]
    {
        va & !LA64_DMW_BASE
    }
    #[cfg(not(target_arch = "loongarch64"))]
    {
        va
    }
}

pub(crate) unsafe fn copy_bytes_exact(src: *const u8, dst: *mut u8, len: usize) {
    core::ptr::copy_nonoverlapping(src, dst, len);
}

/// 构造 satp/PGDL token。
///
/// RISC-V：Sv39 格式（MODE=8 << 60 | root PPN）。
/// LoongArch：直接使用 root PPN，由调用者写入 PGDL CSR。
#[cfg(target_arch = "riscv64")]
fn make_satp(root: PhysPageNum) -> usize {
    (8usize << 60) | root.0
}

#[cfg(not(target_arch = "riscv64"))]
fn make_satp(root: PhysPageNum) -> usize {
    root.0
}

/// 清零新分配的物理页。
pub fn zero_page(ppn: PhysPageNum) {
    let ptr = phys_to_virt(ppn.0 * PAGE_SIZE) as *mut u8;
    unsafe { core::ptr::write_bytes(ptr, 0, PAGE_SIZE); }
}

// ── Architecture helpers (cfg-gated CSR / TLB) ─────────────────────────────

#[cfg(target_arch = "riscv64")]
fn arch_write_satp(token: usize) {
    unsafe {
        core::arch::asm!("csrw satp, {}", in(reg) token);
        core::arch::asm!("sfence.vma");
    }
}

#[cfg(target_arch = "loongarch64")]
fn arch_write_satp(token: usize) {
    let mut pgdl = token << PAGE_BITS;
    unsafe {
        core::arch::asm!("csrwr {0}, 0x19", inout(reg) pgdl => _);
        core::arch::asm!("invtlb 0, $r0, $r0");

        let mut crmd: usize;
        core::arch::asm!("csrrd {0}, 0x0", out(reg) crmd);
        crmd &= !(1 << 3); // DA = 0
        crmd |= 1 << 4;    // PG = 1
        core::arch::asm!("csrwr {0}, 0x0", inout(reg) crmd => _);
    }
}

#[cfg(target_arch = "loongarch64")]
fn arch_current_satp_token() -> usize {
    let pgdl: usize;
    unsafe {
        core::arch::asm!("csrrd {0}, 0x19", out(reg) pgdl);
    }
    pgdl >> PAGE_BITS
}

#[cfg(target_arch = "riscv64")]
fn arch_flush_tlb() {
    unsafe { core::arch::asm!("sfence.vma"); }
}

#[cfg(target_arch = "loongarch64")]
fn arch_flush_tlb() {
    unsafe {
        // dbar 0 flushes the store buffer so the MMU sees the
        // latest PTE writes before we invalidate cached TLB entries.
        core::arch::asm!("dbar 0; invtlb 0, $r0, $r0");
    }
}

#[cfg(target_arch = "riscv64")]
fn arch_fence_i() {
    unsafe { core::arch::asm!("fence.i"); }
}

#[cfg(not(target_arch = "riscv64"))]
fn arch_fence_i() {}

