/// 汇编桩之后的 Rust 入口。dtb_addr 在分页和分配器初始化之前保存。
#[no_mangle]
pub extern "C" fn rust_main(dtb_addr: usize) -> ! {
    _boot_hart_init(dtb_addr);
    spawn_init_task();
    crate::trap_handler::start_timer();

    loop {
        if task::is_shutdown() {
            break;
        }
        task::sched_run_once();
    }

    shutdown()
}

/// 刷新 EXT4 脏数据后走平台关机原语，永不返回。
fn shutdown() -> ! {
    fs::init::mount_table().for_each_ext4(|_, ext4fs| {
        let _ = ext4fs.flush_writeback();
    });
    log::puts("\n[goodos] all done, shutting down\n");
    #[cfg(target_arch = "riscv64")]
    unsafe {
        core::arch::asm!("csrw satp, zero");
    }
    hal::Arch::shutdown()
}

/// 全局子系统初始化（boot hart）。顺序有严格依赖：
/// DTB → 架构 init → 内存 → trap → 任务 → 驱动 → 文件系统。
fn _boot_hart_init(dtb_addr: usize) {
    driver::probe::device_tree::save_dtb_addr(dtb_addr);
    hal::Arch::arch_init();
    log::init();
    log::puts("[boot] goodos kernel start: ");
    log::puts(<Arch as hal::ArchInfo>::name());
    log::puts("\n");
    #[cfg(target_arch = "loongarch64")]
    {
        extern "C" {
            fn __tlb_refill_entry();
        }
        hal::Arch::set_tlb_refill_vector(__tlb_refill_entry as usize);
    }
    mm::init(dtb_addr);
    crate::trap_handler::init();
    task::init();
    driver::manager::init(0);
    fs::init::fs_init();
}

/// 为 init_main 分配内核栈并注册为就绪任务。
/// 调度器条目 0 保留给 idle，后续用户 PID 从 1 开始。
fn spawn_init_task() {
    let npages = 64;
    let base = mm::alloc_pages_contiguous(npages).unwrap().0 * platform::PAGE_SIZE;
    let init_stack_top = base + npages * platform::PAGE_SIZE;
    #[cfg(target_arch = "loongarch64")]
    let (init_sp, init_ra) = (
        mm::phys_to_virt(init_stack_top),
        mm::phys_to_virt(init_main as usize),
    );
    #[cfg(not(target_arch = "loongarch64"))]
    let (init_sp, init_ra) = (init_stack_top, init_main as usize);

    let init_ctx = task::KernelContext {
        sp: init_sp,
        ra: init_ra,
        s0: 0, s1: 0, s2: 0, s3: 0, s4: 0, s5: 0, s6: 0, s7: 0,
        s8: 0, s9: 0, s10: 0, s11: 0,
    };

    task::sched_init(0, task::KernelContext::zeroed());
    task::sched_mark_idle(0);
    task::sched_add(0, init_ctx, 0);
}

/// 首个内核任务：优先 user_init，不可用时 fallback 到其他内嵌程序。
extern "C" fn init_main() -> ! {
    if let Some(tc) = crate::init_proc::find_testcase("user_init") {
        if tc.elf_data.len() > 1024 {
            log::puts("[init] spawning embedded user_init\n");
            let pid = crate::init_proc::spawn_embedded(&tc);
            if pid != 0 {
                task::run_process(pid);
                log::puts("[init] user_init finished\n");
                task::signal_shutdown();
                shutdown();
            }
        }
        log::puts("[init] user_init spawn failed, falling back\n");
    }

    let (list, count) = crate::init_proc::testcase_list();
    for i in 0..count {
        if let Some(ref tc) = list[i] {
            if tc.elf_data.len() > 1024 {
                let pid = crate::init_proc::spawn_embedded(tc);
                if pid != 0 {
                    task::run_process(pid);
                }
            }
        }
    }

    log::puts("[init] all done\n");
    task::signal_shutdown();
    shutdown();
}

